    "Enrollment": true,
    "Remove": true
  },
  "Properties": [
    {
      "Name": "InventoryAll",
      "DisplayName": "InventoryAll",
      "Type": "Bool",
      "DependsOn": null,
      "DefaultValue": "false",
      "Required": true
    },
    {
      "Name": "IgnoreValidation",
      "DisplayName": "IgnoreValidation",
      "Type": "Bool",
